import React from "react";
import bootstrap from "bootstrap";
import "../login/style.css"

const Login = () => {
  return (
    <>
      <section className="container">
        <div className="sub_container">
          <div className="login_heading ">
            <h1 className="login_">Log In</h1>
          </div>
          <div className="login_username"></div>
          <div className="login_username__input"></div>
          <div className="login_password"></div>
          <div className="login_password__input"></div>
          <div className="login_submit"></div>
        </div>
      </section>
    </>
  );
};
export default Login;
